  4	  ChartAxis,
  5	  ChartBar,
  6	  ChartGroup,
  7	  ChartLabel,
  8	  ChartLegend,
  9	  ChartLine,
 10	  ChartScatter,
 11	  ChartStack,
 12	  ChartThemeColor
 13	} from '@patternfly/react-charts/victory';
 14	import * as React from 'react';
 15	import { useTranslation } from 'react-i18next';
 16	import { GenericMetric, NamedMetric } from '../../api/loki';
 17	import { MetricFunction, MetricType } from '../../model/flow-query';
 18	import { localStorageOverviewMetricsDimensionKey, useLocalStorage } from '../../utils/local-storage-hook';
 19	import { getFormattedValue } from '../../utils/metrics';
 20	import {
 21	  ChartDataPoint,
 22	  defaultDimensions,
 23	  Dimensions,
 24	  LegendDataItem,
 25	  observeDimensions,
 26	  toDatapoints
 27	} from '../../utils/metrics-helper';
 28	import { chartVoronoi } from './chart-voronoi';
 29	import './metrics-content.css';
 30	
 31	export interface MetricsGraphProps {
 32	  id: string;
 33	  metricType: MetricType;
 34	  metricFunction: MetricFunction;
 35	  metrics: GenericMetric[] | NamedMetric[];
 36	  limit: number;
 37	  showBar?: boolean;
 38	  showArea?: boolean;
 39	  showLine?: boolean;
 40	  showScatter?: boolean;
 41	  smallerTexts?: boolean;
 42	  itemsPerRow?: number;
 43	  tooltipsTruncate: boolean;
 44	  showLegend?: boolean;
 45	  animate?: boolean;
 46	}
 47	
 48	export const MetricsGraph: React.FC<MetricsGraphProps> = ({
 49	  id,
 50	  metricType,
 51	  metricFunction,
 52	  metrics,
 53	  limit,
 54	  showBar,
 55	  showArea,
 56	  showLine,
 57	  showScatter,
 58	  smallerTexts,
 59	  itemsPerRow,
 60	  tooltipsTruncate,
 61	  showLegend,
 62	  animate
 63	}) => {
 64	  const { t } = useTranslation('plugin__netobserv-plugin');
 65	
 66	  const filteredMetrics = metrics.slice(0, limit);
 67	
 68	  const legendData: LegendDataItem[] = filteredMetrics.map((m, idx) => ({
 69	    childName: `${showBar ? 'bar-' : 'area-'}${idx}`,
 70	    name: (m as NamedMetric).shortName || (m as GenericMetric).name,
 71	    tooltipName:
 72	      (tooltipsTruncate ? (m as NamedMetric).shortName : (m as NamedMetric).fullName) || (m as GenericMetric).name
 73	  }));
 74	
 75	  const topKDatapoints: ChartDataPoint[][] = filteredMetrics.map(toDatapoints);
 76	
 77	  const legentComponent = (
 78	    <ChartLegend
 79	      itemsPerRow={itemsPerRow ? itemsPerRow : 1}
 80	      labelComponent={<ChartLabel className={smallerTexts ? 'small-chart-label' : ''} />}
 81	      data={legendData}
 82	    />
 83	  );
 84	
 85	  const containerRef = React.useRef<HTMLDivElement>(null);
 86	  const [dimensions, setDimensions] = useLocalStorage<Dimensions>(
 87	    `${localStorageOverviewMetricsDimensionKey}${showLegend ? '-legend' : ''}`,
 88	    defaultDimensions
 89	  );
 90	
 91	  React.useEffect(() => {
 92	    return observeDimensions(containerRef, dimensions, setDimensions);
 93	  }, [containerRef, dimensions, setDimensions]);
 94	
 95	  return (
 96	    <div id={`chart-${id}`} className="metrics-content-div" ref={containerRef} data-test-metrics={metrics.length}>
 97	      <Chart
 98	        themeColor={ChartThemeColor.multiUnordered}
 99	        containerComponent={
100	          showLegend
101	            ? chartVoronoi(legendData, (v: number) => getFormattedValue(v, metricType, metricFunction, t))
102	            : undefined
103	        }
104	        legendData={showLegend ? legendData : undefined}
105	        legendOrientation={'horizontal'}
106	        legendPosition="bottom-left"
107	        legendAllowWrap={true}
108	        legendComponent={showLegend ? legentComponent : undefined}
109	        scale={{ x: 'time', y: showBar ? 'linear' : 'sqrt' }}
110	        width={dimensions.width}
111	        height={dimensions.height}
112	        domainPadding={{ x: 0, y: 0 }}
113	        animate={animate}
114	        padding={
115	          showLegend
116	            ? {
117	                bottom: (itemsPerRow && itemsPerRow > 1 ? legendData.length / 2 + 1 : legendData.length) * 25 + 75,
118	                left: 90,
119	                right: 50,
120	                top: 50
121	              }
122	            : {
123	                bottom: 0,
124	                left: 0,
125	                right: 0,
126	                top: 0
127	              }
128	        }
129	      >
130	        <ChartAxis fixLabelOverlap />
131	        <ChartAxis
132	          dependentAxis
133	          showGrid
134	          fixLabelOverlap
135	          tickFormat={y => (showLegend ? getFormattedValue(y, metricType, metricFunction, t) : '')}
136	        />
137	        {showBar && (
138	          <ChartStack>
139	            {topKDatapoints.map((datapoints, idx) => (
140	              <ChartBar name={`bar-${idx}`} key={`bar-${idx}`} data={datapoints} />
141	            ))}
142	          </ChartStack>
143	        )}
144	        {showArea && (
145	          <ChartGroup>
146	            {topKDatapoints.map((datapoints, idx) => (
147	              <ChartArea name={`area-${idx}`} key={`area-${idx}`} data={datapoints} interpolation="monotoneX" />
148	            ))}
149	          </ChartGroup>
150	        )}
151	        {showLine && (
152	          <ChartGroup>
153	            {topKDatapoints.map((datapoints, idx) => (
154	              <ChartLine name={`line-${idx}`} key={`line-${idx}`} data={datapoints} interpolation="monotoneX" />
155	            ))}
156	          </ChartGroup>
157	        )}
158	        {showScatter && (
159	          <ChartGroup>
160	            {topKDatapoints.map((datapoints, idx) => (
161	              <ChartScatter name={`scatter-${idx}`} key={`scatter-${idx}`} data={datapoints} />
162	            ))}
163	          </ChartGroup>
164	        )}
165	      </Chart>
166	    </div>
167	  );
168	};
169	
170	export default MetricsGraph;

