 1	import { render, waitFor } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { metrics } from '../../__tests-data__/metrics';
 5	import { MetricsGraph, MetricsGraphProps } from '../metrics-graph';
 6	
 7	describe('<MetricsContent />', () => {
 8	  const props: MetricsGraphProps = {
 9	    id: 'chart-test',
10	    metricType: 'Bytes',
11	    metricFunction: 'avg',
12	    metrics: metrics.map(m => ({ ...m, fullName: 'whatever', shortName: 'whatever', isInternal: false })),
13	    smallerTexts: false,
14	    limit: 5,
15	    tooltipsTruncate: true
16	  };
17	
18	  it('should render component', async () => {
19	    const { container } = render(<MetricsGraph {...props} />);
20	    expect(container.querySelector('#chart-chart-test')).toBeInTheDocument();
21	    expect(container.querySelector('svg')).toBeInTheDocument();
22	  });
23	
24	  it('should render bar', async () => {
25	    const { container } = render(<MetricsGraph {...props} showBar={true} />);
26	    expect(container.querySelector('svg')).toBeInTheDocument();
27	    await waitFor(() => {
28	      const svg = container.querySelector('svg')!;
29	      expect(svg.querySelectorAll('[role="presentation"]').length).toBeGreaterThan(0);
30	    });
31	  });
32	
33	  it('should render area', async () => {
34	    const { container } = render(<MetricsGraph {...props} showArea={true} />);
35	    expect(container.querySelector('svg')).toBeInTheDocument();
36	    await waitFor(() => {
37	      expect(container.querySelectorAll('path').length).toBeGreaterThan(0);
38	    });
39	  });
40	
41	  it('should render area with scatter', async () => {
42	    const { container } = render(<MetricsGraph {...props} showArea={true} showScatter={true} />);
43	    expect(container.querySelector('svg')).toBeInTheDocument();
44	    await waitFor(() => {
45	      const pathCount = container.querySelectorAll('path').length;
46	      expect(pathCount).toBeGreaterThan(0);
47	    });
48	  });
49	});

